#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int pos1 = -1, posN = -1;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x == 1) pos1 = i;
            if (x == N) posN = i;
        }
        int ans = pos1 + (N - 1 - posN) - (pos1 > posN ? 1 : 0);
        printf("%d\n", ans);
    }
    return 0;
}

